{
  "title": "S3 बकेट पॉलिसी",
  "group": "S3 सुरक्षा",
  "options": [
    {
      "text": "नए बकेट्स को पब्लिक बनाएं",
      "hint": "सबसे पहले न्यूनतम विशेषाधिकार (Least Privilege) का सिद्धांत अपनाएं।"
    },
    {
      "text": "ACLs पर पूर्ण नियंत्रण के लिए S3 को ऑन-प्रेमिसेस ले जाएं"
    },
    {
      "text": "डेटा को प्राइवेट ब्लॉकचेन पर ले जाएं",
      "hint": "मज़ाक कर रहे हैं, है न?"
    },
    {
      "text": "न्यूनतम विशेषाधिकार सिद्धांत का उपयोग करें"
    },
    {
      "text": "ज़रूरी एक्सेस सुनिश्चित करने के लिए पॉलिसी वाइल्डकार्ड्स का उपयोग करें",
      "hint": "😯 नहीं!"
    }
  ],
  "questionProse": [
    "S3 बकेट परमिशंस के लिए अनुशंसित दृष्टिकोण क्या है?"
  ],
  "explanationProse": [
    "लगभग सभी सिस्टम्स में, \"न्यूनतम विशेषाधिकार\" (least privilege) डिज़ाइन को अपनाना सिस्टम की सुरक्षा को मजबूत करने और भविष्य के लिए तैयार करने का एक प्रमुख तरीका है। किसी मौजूदा सिस्टम को लॉक डाउन करने की कोशिश करना लगभग उतना ही मुश्किल है, जितना किसी पूरी ऑफिस बिल्डिंग को नई फाउंडेशन पर शिफ्ट करना।\n\n  S3 बकेट्स भी इससे अलग नहीं हैं। न्यूनतम विशेषाधिकार के सिद्धांत को लागू करने के लिए, बिना किसी परमिशन के शुरुआत करें और केवल ज़रूरी एक्सेस ही प्रदान करें। एक्सेस को कंट्रोल करने के लिए IAM roles और policies का उपयोग करें और बकेट परमिशंस का नियमित रूप से ऑडिट करें।\n\n  सुरक्षा के सर्वोत्तम तरीके:\n  - न्यूनतम विशेषाधिकार सिद्धांत लागू करें\n  - बिना किसी परमिशन के शुरुआत करें\n  - केवल ज़रूरी एक्सेस प्रदान करें\n  - IAM roles और policies का उपयोग करें\n  - बकेट परमिशंस का नियमित ऑडिट करें\n\n  ऐसी सेटिंग्स से बचें जो बहुत ज़्यादा खुली हों और संवेदनशील डेटा को एक्सपोज़ कर सकती हैं।\n\n  [S3 सुरक्षा सर्वोत्तम प्रथाएँ](https://aws.amazon.com/s3/security/)"
  ]
}
